var Friend_data=[],Friend_list=[];function Friend(e){showLoading((Friend_data={el:e.el,url:e.url,type:e.type,repo:e.repo,sort:e.sort,owner:e.owner,noimg:e.noimg||"https://cdn.jsdelivr.net/gh/abbw/CDN/img/guest.jpg",ldimg:e.ldimg||"https://cdn.jsdelivr.net/gh/abbw/CDN/img/ld.gif"}).el),getFriends(),HideLoading()}function createFriend(e){document.querySelector(""+Friend_data.el).insertAdjacentHTML("beforeBegin",`<div class="friend-item"><a onmouseover="displayImg('https://cdn.jsdelivr.net/gh/abbw/CDN/img/screenshot/blog_links.jpg')" onmouseout="hideImg()" class="friend-item-card" href="${Friend_data.url}" title="友链自助申请，无需审核" target="_blank"><div class="friend-item-content"><div class="friend-avatar"><img style="border-radius:50%" src="https://cdn.jsdelivr.net/gh/abbw/CDN/img/who.jpg"></div><div class="friend-text"><div class="friend-name">自助申请</div><div class="friend-dsc">Issue自动添加，无需审核</div></div></div><img id="Screenshot"></a></div>`);for(let i in e)document.querySelector(""+Friend_data.el).insertAdjacentHTML("beforeEnd",e[i])}function getFriends(){"github"==Friend_data.type?url="api.github.com":url="gitee.com/api/v5",fetch(`https://${url}/repos/${Friend_data.owner}/${Friend_data.repo}/issues?state=open&sort=created&direction=${Friend_data.sort}&page=1&per_page=100`).then((e=>e.json())).then((e=>{if(e)if(e.hasOwnProperty("message"))showToast("自助友链请求出错，日志如下：<br>"+e.message);else{for(var i in e){var t=getBody(e[i].body,"link"),r=getBody(e[i].body,"name"),d=getBody(e[i].body,"descr"),n=getBody(e[i].body,"avatar"),s=`<div class="friend-item"><a onmouseover="displayImg('${getScreenshot(getBody(e[i].body,"Screenshot"),t)}')" onmouseout="hideImg()" class="friend-item-card" href="${t}" title="${r}" target="_blank"><div class="friend-item-content"><div class="friend-avatar"><img style="border-radius:50%" src="${n}" onerror="this.onerror=null;this.src='${Friend_data.noimg}'"></div><div class="friend-text"><div class="friend-name">${r}</div><div class="friend-dsc">${d}</div></div></div><img id="Screenshot"></a></div>`;Friend_list.push(s)}createFriend(Friend_list),console.log("%c 自助友链Issues数量: %c "+Friend_list.length+" 个 ","color: #fff; background:#4285f4;","background:#66CCFF;")}})).catch((e=>showToast("自助友链请求出错，日志如下：<br>"+e)))}function showLoading(e){document.querySelector(""+e).insertAdjacentHTML("beforeBegin",`<div class="loader" style="width:150px;height:150px;margin:0 auto"><img src='${Friend_data.ldimg}'></div>`)}function HideLoading(e){document.querySelector(".loader").style.display="none"}function getBody(e,i){var t=new RegExp(String.raw`${i}:[^\n]*\n`),r=new RegExp(String.raw`(${i}:[\s]*|[\r\n]*)`,"g");let d="该参数有误";return(e=e.match(t))&&e.length>0&&(d=e[0].replace(r,"")),d}function getScreenshot(e,i){return"该参数有误"!=e?e:"https://image.thum.io/get/width/1024/crop/768/"+i}